external_knowledge:
- 'Navigators guiding the ship': refers to the users who have accessed the monitoring station. ;
- 'Waters of station 1': metaphor for the specific monitoring station with the identifier `station_id` 1. ;
- 'Average quality of the stars they have charted': refers to the average quality rating of the data entries assessed by users of the station. ;
- 'Storm warnings currently on the horizon for this vessel': refers to the active alerts for the station, indicating current issues that need attention.

sql:
SELECT * 
FROM station_metrics 
WHERE station_id = 'specific_station_id';

SELECT station_id, AVG(uptime_percentage) AS average_uptime
FROM station_metrics
GROUP BY station_id;

external_knowledge:
- 'Stations' refer to monitoring stations;
- 'Operators' are the users responsible for these stations;
- 'Warnings' are the alerts generated by the stations;
- 'Quality reviews' refer to the quality assessments of the data collected by the stations;
- 'Operational uptime' is the average percentage of time these stations function correctly;
- 'Repairs' indicate if maintenance is needed for these stations.

sql:
SELECT station_id, uptime_percentage
FROM station_metrics
ORDER BY uptime_percentage DESC;

SELECT AVG(uptime_percentage) AS average_uptime_percentage,
       AVG(data_reliability) AS average_data_reliability
FROM station_metrics;

SELECT metric_id, uptime_percentage
FROM station_metrics
WHERE uptime_percentage < 99.0;
